mapper.select:
/* 알림 이벤트별 설정: 내 설정 전체 조회 */
SELECT USR_NTF_EVT_STG_SN AS usrNtfEvtStgSn, USR_SN AS usrSn, NTF_EVT_CD AS ntfEvtCd,
       USR_NTF_EVT_STG_INAPP_YN AS usrNtfEvtStgInappYn, USR_NTF_EVT_STG_EMAIL_YN AS usrNtfEvtStgEmailYn,
       USR_NTF_EVT_STG_REG_DT AS usrNtfEvtStgRegDt, USR_NTF_EVT_STG_UPDT_DT AS usrNtfEvtStgUpdtDt
FROM USER_NOTIFICATION_EVENT_SETTING
WHERE USR_SN = #{usrSn}

/* 알림 이벤트별 설정: 이벤트 1건 조회 */
SELECT USR_NTF_EVT_STG_SN AS usrNtfEvtStgSn, USR_SN AS usrSn, NTF_EVT_CD AS ntfEvtCd,
       USR_NTF_EVT_STG_INAPP_YN AS usrNtfEvtStgInappYn, USR_NTF_EVT_STG_EMAIL_YN AS usrNtfEvtStgEmailYn,
       USR_NTF_EVT_STG_REG_DT AS usrNtfEvtStgRegDt, USR_NTF_EVT_STG_UPDT_DT AS usrNtfEvtStgUpdtDt
FROM USER_NOTIFICATION_EVENT_SETTING
WHERE USR_SN = #{usrSn} AND NTF_EVT_CD = #{ntfEvtCd}
